/**
 * SRD Closer - Main Application Entry Point
 * Enterprise Sales Automation with AI
 *
 * Framework: Synkra AIOS v4.31.0
 * Language: JavaScript (ES Module)
 */

import express from 'express';
import bodyParser from 'body-parser';
import cors from 'cors';
import dotenv from 'dotenv';

// Load environment variables
dotenv.config();

const app = express();
const PORT = process.env.PORT || 3000;

/**
 * Middleware Configuration
 */

// CORS
app.use(cors({
  origin: process.env.CORS_ORIGIN || '*',
  credentials: true,
}));

// Body Parser
app.use(bodyParser.json({ limit: '10mb' }));
app.use(bodyParser.urlencoded({ limit: '10mb', extended: true }));

/**
 * Routes
 */

// Health Check
app.get('/health', (req, res) => {
  res.json({
    status: 'ok',
    timestamp: new Date().toISOString(),
    service: 'srd-closer',
    version: '1.0.0',
  });
});

// API Routes
app.get('/api/status', (req, res) => {
  res.json({
    service: 'SRD Closer API',
    status: 'running',
    framework: 'AIOS v4.31.0',
    environment: process.env.NODE_ENV || 'development',
  });
});

// Root Route
app.get('/', (req, res) => {
  res.json({
    message: 'Welcome to SRD Closer',
    description: 'Enterprise Sales Automation System',
    version: '1.0.0',
    docs: '/api/docs',
  });
});

/**
 * Error Handling
 */

// 404 Handler
app.use((req, res) => {
  res.status(404).json({
    error: 'Not Found',
    path: req.path,
    method: req.method,
  });
});

// Error Handler
app.use((err, req, res, next) => {
  console.error('Error:', err.message);
  res.status(err.status || 500).json({
    error: err.message || 'Internal Server Error',
    status: err.status || 500,
  });
});

/**
 * Server Startup
 */

if (process.env.NODE_ENV !== 'test') {
  app.listen(PORT, () => {
    console.log(`✅ Server running on http://localhost:${PORT}`);
    console.log(`📊 Health check: http://localhost:${PORT}/health`);
    console.log(`🎯 API Status: http://localhost:${PORT}/api/status`);
  });
}

export default app;

