#!/usr/bin/env node

/**
 * Build Script for SRD Closer
 * Transpiles source files and creates distribution bundle
 *
 * Usage: npm run build
 */

import fs from 'fs-extra';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const rootDir = path.join(__dirname, '..');
const srcDir = path.join(rootDir, 'src');
const distDir = path.join(rootDir, 'dist');

async function build() {
  try {
    console.log('🔨 Building SRD Closer...');
    console.log(`📁 Source: ${srcDir}`);
    console.log(`📦 Output: ${distDir}`);

    // Clean dist directory
    console.log('🧹 Cleaning dist directory...');
    await fs.remove(distDir);
    await fs.ensureDir(distDir);

    // Copy source files
    console.log('📋 Copying source files...');
    await fs.copy(srcDir, distDir);

    // Copy public assets
    const publicDir = path.join(rootDir, 'public');
    if (await fs.pathExists(publicDir)) {
      console.log('🎨 Copying public assets...');
      await fs.copy(publicDir, path.join(distDir, 'public'));
    }

    // Create package info file
    const packageJson = await fs.readJson(path.join(rootDir, 'package.json'));
    const buildInfo = {
      name: packageJson.name,
      version: packageJson.version,
      buildTime: new Date().toISOString(),
      nodeVersion: process.version,
      environment: process.env.NODE_ENV || 'development',
    };

    await fs.writeJson(
      path.join(distDir, 'BUILD_INFO.json'),
      buildInfo,
      { spaces: 2 }
    );

    console.log('✅ Build completed successfully!');
    console.log(`📦 Distribution ready at: ${distDir}`);
    console.log(`📊 Build Info: ${path.join(distDir, 'BUILD_INFO.json')}`);

  } catch (error) {
    console.error('❌ Build failed:', error.message);
    process.exit(1);
  }
}

build();

